import { randomUUID } from 'node:crypto';

import { Injectable, Logger } from '@nestjs/common';
import { Knex } from 'knex';
import { InjectConnection } from 'nest-knexjs';

import { KNEX_READ_CONNECTION, KNEX_WRITE_CONNECTION } from '@modules/db/db.constant';
import {
	IJiraInstallationBase,
	IJiraInstallationCreate,
	JiraInstallationStatus,
} from '@modules/jira/types/jira-installation.interface';

import { TABLE_NAME_JIRA_INSTALLATIONS } from '@constants/db.constant';

@Injectable()
export class JiraInstallationModel {
	private readonly logger = new Logger(JiraInstallationModel.name);
	private readonly tableName = TABLE_NAME_JIRA_INSTALLATIONS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async create({ data }: { data: IJiraInstallationCreate }): Promise<IJiraInstallationBase> {
		try {
			const _id = randomUUID();
			const [created] = await this.knexWrite<IJiraInstallationBase>(this.tableName)
				.insert({
					_id,
					...data,
					status: JiraInstallationStatus.ACTIVE,
					created_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				})
				.returning('*');

			if (!created) throw new Error('Failed to create jira installation');

			this.logger.debug(`Created jira installation ${_id}`);
			return created;
		} catch (error) {
			this.logger.error(`Failed to create jira installation: ${(error as Error).message}`);
			throw error;
		}
	}

	async findAllActive(): Promise<IJiraInstallationBase[]> {
		try {
			return await this.knexRead<IJiraInstallationBase>(this.tableName)
				.where({ status: JiraInstallationStatus.ACTIVE })
				.select('*');
		} catch (error) {
			this.logger.error(`Failed to find active installations: ${(error as Error).message}`);
			throw error;
		}
	}

	async findById({ id }: { id: string }): Promise<IJiraInstallationBase | null> {
		try {
			const result = await this.knexRead<IJiraInstallationBase>(this.tableName)
				.where({ _id: id })
				.first();
			return result ?? null;
		} catch (error) {
			this.logger.error(`Failed to find installation ${id}: ${(error as Error).message}`);
			throw error;
		}
	}

	async updateTokens({
		id,
		accessToken,
		refreshToken,
		tokenExpiresAt,
	}: {
		id: string;
		accessToken: string;
		refreshToken: string;
		tokenExpiresAt: Date;
	}): Promise<void> {
		try {
			await this.knexWrite<IJiraInstallationBase>(this.tableName)
				.where({ _id: id })
				.update({
					access_token: accessToken,
					refresh_token: refreshToken,
					token_expires_at: tokenExpiresAt,
					updated_at: this.knexWrite.fn.now(),
				});
		} catch (error) {
			this.logger.error(`Failed to update tokens for ${id}: ${(error as Error).message}`);
			throw error;
		}
	}

	async markNeedsReauth({ id }: { id: string }): Promise<void> {
		try {
			await this.knexWrite<IJiraInstallationBase>(this.tableName)
				.where({ _id: id })
				.update({
					status: JiraInstallationStatus.NEEDS_REAUTH,
					updated_at: this.knexWrite.fn.now(),
				});
		} catch (error) {
			this.logger.error(`Failed to mark needs_reauth for ${id}: ${(error as Error).message}`);
			throw error;
		}
	}

	async markUninstalled({
		id,
		companyId,
	}: {
		id: string;
		companyId: string;
	}): Promise<void> {
		try {
			await this.knexWrite<IJiraInstallationBase>(this.tableName)
				.where({ _id: id, company_id: companyId })
				.update({
					status: JiraInstallationStatus.UNINSTALLED,
					updated_at: this.knexWrite.fn.now(),
				});
			this.logger.debug(`Marked jira installation ${id} as uninstalled`);
		} catch (error) {
			this.logger.error(`Failed to mark uninstalled for ${id}: ${(error as Error).message}`);
			throw error;
		}
	}
}

