import { IJiraProjectBase } from '@modules/jira/types/jira-installation.interface';

import { TABLE_NAME_JIRA_PROJECTS } from '@constants/db.constant';

@Injectable()
export class JiraProjectModel {
	private readonly logger = new Logger(JiraProjectModel.name);
	private readonly tableName = TABLE_NAME_JIRA_PROJECTS;

	constructor(
		@InjectConnection(KNEX_READ_CONNECTION) private readonly knexRead: Knex,
		@InjectConnection(KNEX_WRITE_CONNECTION) private readonly knexWrite: Knex,
	) {}

	async upsertMany({
		installationId,
		projects,
	}: {
		installationId: string;
		projects: IJiraApiProject[];
	}): Promise<void> {
		if (projects.length === 0) return;

		try {
			const rows = projects.map((p) => ({
				_id: randomUUID(),
				installation_id: installationId,
				project_key: p.key,
				project_id: p.id,
				name: p.name,
				project_type: p.projectTypeKey,
				created_at: this.knexWrite.fn.now(),
				updated_at: this.knexWrite.fn.now(),
			}));

			await this.knexWrite<IJiraProjectBase>(this.tableName)
				.insert(rows)
				.onConflict(['installation_id', 'project_id'])
				.merge(['project_key', 'name', 'project_type', 'updated_at']);

			this.logger.debug(`Upserted ${projects.length} projects for installation ${installationId}`);
		} catch (error) {
			this.logger.error(`Failed to upsert projects: ${(error as Error).message}`);
			throw error;
		}
	}

	async findByInstallationId({
		installationId,
	}: {
		installationId: string;
	}): Promise<IJiraProjectBase[]> {
		try {
			return await this.knexRead<IJiraProjectBase>(this.tableName)
				.where({ installation_id: installationId })
				.select('*');
		} catch (error) {
			this.logger.error(`Failed to find projects for installation ${installationId}: ${(error as Error).message}`);
			throw error;
		}
	}

	async updateLastSyncedAt({ id }: { id: string }): Promise<void> {
		try {
			await this.knexWrite<IJiraProjectBase>(this.tableName)
				.where({ _id: id })
				.update({
					last_synced_at: this.knexWrite.fn.now(),
					updated_at: this.knexWrite.fn.now(),
				});
		} catch (error) {
			this.logger.error(`Failed to update last_synced_at for project ${id}: ${(error as Error).message}`);
			throw error;
		}
	}

	async deleteByProjectId({
		installationId,
		projectId,
	}: {
		installationId: string;
		projectId: string;
	}): Promise<void> {
		try {
			await this.knexWrite<IJiraProjectBase>(this.tableName)
				.where({ installation_id: installationId, project_id: projectId })
				.delete();
		} catch (error) {
			this.logger.error(`Failed to delete project ${projectId}: ${(error as Error).message}`);
			throw error;
		}
	}
}

